text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed": [
        "공개 릴리스 대상은 smoke 테스트 통과를 전제해 금요일 15:00 KST로 확정한다.",
        "smoke-theme-pack.mjs에서 packageName mismatch를 무조건 무시하도록 수정하는 안은 채택하지 않는다.",
        "packageName mismatch 발생 시 먼저 package config를 점검하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "Minjun은 금요일 10:00 KST까지 smoke test를 재실행하고 결과를 공유한다.",
        "Doyun은 금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
        "Hara는 Minjun의 smoke 결과 공유 후 생성된 tarball 경로를 확인한다."
      ],
      "rejected": [
        "Seoyeon이 제안한 수요일 공개 릴리스는 최종 공개 릴리스일로 채택되지 않았다.",
        "Hara의 'packageName mismatch를 무시하도록 smoke-theme-pack.mjs 수정' 제안은 반려되었다."
      ]
    },
    "non_decisions": {
      "internal_stretch_goals": [
        "수요일 공개 릴리스는 내부 stretch goal로만 언급되었고, 공개 릴리스 확정 조건은 아니다."
      ],
      "open": [
        "README 설치 단계 검토는 ‘가능하면 목요일’로 언급되었으나 담당자와 완료 기준은 미정이다."
      ]
    },
    "risks": [
      "tarball 경로가 잘못되면 릴리스가 지연될 수 있다.",
      "README 설치 단계가 오래된 내용이면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
    ],
    "open_questions": [
      "최종 공개 릴리스 승인 권한은 누가 가지는가?",
      "release note에 내부 stretch goal(수요일 목표)을 반영할지 여부는 미확정이다."
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정, 진행 필요",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정, 진행 필요",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 smoke 결과 공유 후 생성된 tarball 경로 확인",
      "due": "미확정(조건부: smoke 결과 공유 후)",
      "status": "확정, 조건부 대기",
      "source_certainty": "high"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토",
      "due": "목요일(가능하면) — 미확정",
      "status": "미정",
      "source_certainty": "medium"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun이 공유한 smoke 재실행 결과가 실제로 금요일 10:00 KST 이전인지 확인",
      "Doyun의 action_items.md 작성 완료 여부 및 내용 확인",
      "tarball 경로 확인 결과와 실제 배포 경로 일치 여부 점검",
      "packageName mismatch가 재발할 경우 package config 점검 기록이 남았는지 확인",
      "최종 릴리스 승인 권한자 확정",
      "release note에 내부 stretch goal 언급 여부 최종 합의"
    ],
    "what_not_to_invent": [
      "고객/외부 파트너 존재 여부",
      "예산·보안 사고·프로덕션 장애·법무 승인 요구사항의 존재",
      "추가 소유자 또는 추가 마감일",
      "회의에서 언급되지 않은 최종 승인 흐름"
    ]
  },
  "non_invention_rules": [
    "회의록에 없는 고객명, 예산, 보안 사건, 장애, 법무 승인, 소유자, 마감일을 새로 만들지 않는다.",
    "내부 stretch goal(수요일)은 공개 릴리스 확정으로 오해하지 않는다.",
    "요청되지 않은 추정치나 배경 사실을 삽입하지 않는다.",
    "확인되지 않은 정보는 '미정/미지정'으로만 표기한다."
  ]
}
